<?php session_start();$widget_select_plage = new FormLayout('Selectionner une plage', 6);$widget_select_plage->setFormControls('form_ral', '', 'get');$select = new Select('ral');$select->onChange("$('#form_ral').submit();");$select->setSelected($get_ral);$select->withSearch();foreach ($tab_ral AS $ral)    $select->addOption($ral, $ral * 1000);$widget_select_plage->addLine('Ral :', $select);$modify_button = new Button('Modifier les stocks', 'javascript:void()');$modify_button->onClick("toEdit();");$modify_button->setClasse('btn-primary');$widget_select_plage->addLine('', $modify_button, false, 'actions');echo $widget_select_plage;?><?phpif(right('colors', 3)){    ?><script>    function toEdit()    {        <?php        foreach ($tab_colors AS $value_color)        {            foreach ($tab_aspects AS $value_aspect)            {                ?>        var val = document.getElementById('cell_<?php echo $value_color['id'];?>_<?php echo $value_aspect['id'];?>').innerText;        document.getElementById('cell_<?php echo $value_color['id'];?>_<?php echo $value_aspect['id'];?>').innerHTML = '<input id="input_<?php echo $value_color['id'];?>_<?php echo $value_aspect['id'];?>" type="text" value="'+val+'" />';                        <?php            }        }        $apply_button = new Button('Appliquer les modifications', 'javascript:void()');        $apply_button->onClick("Valid();");        $apply_button->setClasse('btn-success');        ?>        document.getElementById('actions').innerHTML = '<div class="form-group " id="actions" style=""> <label class="col-md-3 control-label"></label><div class="col-md-9"><?php echo $apply_button; ?></div></div>';    }        function Valid()    {                <?php        foreach ($tab_colors AS $value_color)        {            foreach ($tab_aspects AS $value_aspect)            {                ?>                var val = document.getElementById('input_<?php echo $value_color['id'];?>_<?php echo $value_aspect['id'];?>').value;        document.getElementById('cell_<?php echo $value_color['id'];?>_<?php echo $value_aspect['id'];?>').innerHTML = val;        klient = new XMLHttpRequest();        klient.open("GET", "./ajax/edit_stocks.php?id_c=<?php echo $value_color['id'];?>&id_a=<?php echo $value_aspect['id'];?>&stock="+val);        klient.send(null);                <?php            }        }        ?>        document.getElementById('actions').innerHTML = '<div class="form-group " id="actions" style=""> <label class="col-md-3 control-label"></label><div class="col-md-9"><?php echo $modify_button;?></div></div>';    }</script>    <?php}$widget_table = new WidgetBox(COULEURS_TAB_COLORS_STOCKS);$tableau = new HtmlTable();$tableau->addTSection("thead");$tableau->addRow();$tableau->addCell('Couleur', '', 'thead');foreach ($tab_aspects AS $value_aspect)    $tableau->addCell($value_aspect['name'], '', 'thead');$tableau->addTSection('tbody');$i = 0;foreach ($tab_colors AS $value_color){    $tableau->addRow();    $tableau->addCell($value_color['name'] . ' ( Ral : ' . $value_color['ral'].')');    foreach ($tab_aspects AS $value_aspect)    {        if ($tab_stocks[$value_color['id']][$value_aspect['id']] == '')            $stock = '0';        else            $stock = $tab_stocks[$value_color['id']][$value_aspect['id']];        $tableau->addCell($stock, '', '', Array('id' => 'cell_'.$value_color['id'] . '_' . $value_aspect['id']));    }    $i++;    if($i  == 10)    {        $tableau->addRow();        $tableau->addCell('Couleur', '', 'thead');        foreach ($tab_aspects AS $value_aspect)            $tableau->addCell($value_aspect['name'], '', 'thead');        $tableau->addTSection('tbody');        $i = 0;    }}$widget_table->setContent($tableau, false);$row = new Row($widget_table);echo $row;?>